let saudacao: string = "Olá, mundo!";
console.log(saudacao);

let comprimento: number = saudacao.length;
console.log(comprimento);

let nome: string = "Aria";
let frase: string = nome.toUpperCase();
console.log(frase);

console.log(nome.toLowerCase());

let vida: number = 100;
let dano: number = 35;
let vidaRestante: number = vida - dano;
console.log(vidaRestante);

let dobro: number = dano * 2;
console.log(dobro);

// Resto da divisão (módulo)
let resto: number = 10 % 3;
console.log(resto);

// Útil para saber se um número é par:
let numero: number = 8;
let ehPar: boolean = numero % 2 === 0;
console.log(ehPar);

let temEscudo: boolean = true;
let estaEnvenenado: boolean = false;

console.log(temEscudo);
console.log(estaEnvenenado);

// Comparações geram booleans:
let vida: number = 30;
let estaCritico: boolean = vida < 50;
console.log(estaCritico);

let heroi: string = "Aria";
let nivel: number = 5;

// Com concatenação (chato):
console.log("Herói: " + heroi + " | Nível: " + nivel);

// Com template literal (muito melhor!):
console.log(`Herói: ${heroi} | Nível: ${nivel}`);

let preco: number = 49.9;
let quantidade: number = 3;

console.log(`Total: R$ ${preco * quantidade}`);
console.log(`Tem desconto? ${preco * quantidade > 100 ? "Sim!" : "Não"}`);

